(function (window, document) {
  const MONTHS_LONG_ID = ['Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni', 'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'];
  const MONTHS_SHORT_ID = ['Jan', 'Feb', 'Mar', 'Apr', 'Mei', 'Jun', 'Jul', 'Agu', 'Sep', 'Okt', 'Nov', 'Des'];

  function computeRootPrefix() {
    try {
      if (typeof window.__IKSASS_ROOT_PREFIX === 'string') return window.__IKSASS_ROOT_PREFIX;
      const parts = (window.location.pathname || '/').split('/').filter(Boolean);
      const last = parts[parts.length - 1] || '';
      if (last.includes('.')) parts.pop();
      return '../'.repeat(Math.max(0, parts.length));
    } catch (_) {
      return '';
    }
  }

  function getRootPrefix() {
    return computeRootPrefix();
  }

  function toRootUrl(value) {
    const raw = String(value || '').trim();
    const rootPrefix = getRootPrefix();
    if (!raw) return '';
    if (/^(https?:)?\/\//i.test(raw) || raw.startsWith('data:') || raw.startsWith('#')) return raw;
    if (raw.startsWith('/')) return rootPrefix + raw.slice(1);
    return rootPrefix + raw.replace(/^\.+\//, '');
  }

  function resolveUrl(value) {
    const raw = String(value || '').trim();
    if (!raw) return '';
    try {
      return new URL(raw, document.baseURI || window.location.href).toString();
    } catch (_) {
      return raw;
    }
  }

  function escapeHtml(value) {
    return String(value || '')
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
  }

  function normalizeText(value) {
    return String(value || '').toLowerCase();
  }

  function safeISODate(value) {
    const text = String(value || '').trim();
    return /^\d{4}-\d{2}-\d{2}$/.test(text) ? text : '';
  }

  function parseISODate(value) {
    const iso = safeISODate(value);
    if (!iso) return null;
    const date = new Date(iso + 'T00:00:00');
    return Number.isNaN(date.getTime()) ? null : date;
  }

  function formatDateIDLong(value) {
    const date = parseISODate(value);
    if (!date) return safeISODate(value) || '';
    return date.getDate() + ' ' + MONTHS_LONG_ID[date.getMonth()] + ' ' + date.getFullYear();
  }

  function formatDateIDShort(value) {
    const date = parseISODate(value);
    if (!date) return '';
    const day = String(date.getDate()).padStart(2, '0');
    return day + ' ' + MONTHS_SHORT_ID[date.getMonth()] + ' ' + date.getFullYear();
  }

  function getDateBadge(value) {
    const date = parseISODate(value);
    if (!date) return null;
    return {
      day: String(date.getDate()).padStart(2, '0'),
      month: MONTHS_SHORT_ID[date.getMonth()],
    };
  }

  async function fetchJson(path, options) {
    const res = await fetch(toRootUrl(path), Object.assign({ cache: 'no-store' }, options || {}));
    if (!res.ok) throw new Error('Failed to load ' + path + ' (' + res.status + ')');
    return res.json();
  }

  window.IKSASS = Object.assign(window.IKSASS || {}, {
    getRootPrefix,
    toRootUrl,
    resolveUrl,
    escapeHtml,
    normalizeText,
    safeISODate,
    formatDateIDLong,
    formatDateIDShort,
    getDateBadge,
    fetchJson,
  });
})(window, document);
